local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxMemoryStoreCtrl:LxBaseCtrl
local LxMemoryStoreCtrl = classX("LxMemoryStoreCtrl", LxBaseCtrl)

function LxMemoryStoreCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

    self._initMemoryShardRef = {}
end

function LxMemoryStoreCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

function LxMemoryStoreCtrl:GetMemoryShardBelongCard(cardRefId)
    local list = self._initMemoryShardRef[cardRefId]
    if not list then
        list = {}
        local ref = GameTable.MemoryShardRef
        for k,v in pairs(ref) do
            if v.belongCard == cardRefId then
                table.insert(list,v)
            end
        end
        table.sort(list,function(a, b) return a.sort < b.sort end)
        self._initMemoryShardRef[cardRefId] = list
    end
    return list
end

function LxMemoryStoreCtrl:GetMemoryShardNum(cardRefId)
    local list = self:GetMemoryShardBelongCard(cardRefId) or {}
    return #list
end

function LxMemoryStoreCtrl:CheckMemoryShardAllAct(cardRefId)
    local card = ModuleCenter.MemoryStore:GetMemoryCard(cardRefId)
    if not card then return false end

    if card.takeReward then return false end

    local list = self:GetMemoryShardBelongCard(cardRefId)
    if not list or #list < 1 then return false end

    local shardRefIdsMap = card.shardRefIdsMap or {}
    for i,v in ipairs(list) do
        if not shardRefIdsMap[v.refId] then
            return false
        end
    end
    return true
end



function LxMemoryStoreCtrl:CheckMemoryShardIsFull(cardRefId)
    local card = ModuleCenter.MemoryStore:GetMemoryCard(cardRefId)
    if not card then return false end
    local list = self:GetMemoryShardBelongCard(cardRefId)
    return #card.shardRefIds >= #list
end

function LxMemoryStoreCtrl:GetMySelfMemoryShardIds()
    local memoryCardsMap = ModuleCenter.MemoryStore:GetMemoryCards()
    if not memoryCardsMap then return {} end
    local list = {}
    for k,card in pairs(memoryCardsMap) do
        for i,v in ipairs(card.shardRefIds) do
            table.insert(list,v)
        end
    end
    return list
end

function LxMemoryStoreCtrl:GetMemoryShardPayList(refId)
    local cardShardList = self:GetMemoryShardBelongCard(refId)
    if cardShardList and #cardShardList > 0 then
        local card = ModuleCenter.MemoryStore:GetMemoryCard(refId)
        local shardRefIds = card and card.shardRefIds or {}
        if #shardRefIds < #cardShardList then
            local maxRefId
            for i,v in ipairs(shardRefIds) do
                if not maxRefId then
                    maxRefId = v
                elseif maxRefId < v then
                    maxRefId = v
                end
            end
            ---@type V_MemoryShardRef
            local ref
            if maxRefId then
                ref = GameTable.MemoryShardRef[maxRefId]
            else
                ref = cardShardList[1]
            end
            if ref and ref.nextShard > 0 then
                if ref.cost and #ref.cost > 0 then
                    return LxDataHelper.ParseItemList(ref.cost)
                end
            end
        end
    end
    return {}
end

function LxMemoryStoreCtrl:CheckMemoryRedPoint()
    local ref = GameTable.MemoryCardRef
    for k,v in pairs(ref) do
        if CtrlCenter.MemoryStore:CheckMemoryShardAllAct(k) then
            --- 未领取所有激活的奖励
            return true
        end
        if self:CheckActMemoryShardRefId(k) then
            --- 激活下一个卡片的消耗是否满足
            return true
        end
    end
    return false
end

function LxMemoryStoreCtrl:CheckActMemoryShardRefId(refId)
    local payList = self:GetMemoryShardPayList(refId) or {}
    if #payList > 0 and CtrlCenter.Item:CheckItemListEnough(payList) then
        return true
    end
    return false
end

function LxMemoryStoreCtrl:CheckNextMemoryShardRefId(refId)
    local ref = GameTable.MemoryCardRef[refId]
    if not ref then return false end
    local priorCard = ref.priorCard
    local beforeCard = ModuleCenter.MemoryStore:GetMemoryCard(priorCard)
    if not beforeCard then return false end
    local payList = self:GetMemoryShardPayList(refId) or {}
    if #payList > 0 and CtrlCenter.Item:CheckItemListEnough(payList) then
        return true
    end
    return false
end


return LxMemoryStoreCtrl